import React from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { Menu, User } from 'lucide-react';

const Navbar = () => {
    const { user, logout } = useAuth();

    return (
        <nav className="fixed top-0 w-full z-50 glass-card !rounded-none !border-t-0 !border-x-0">
            <div className="container mx-auto px-4 py-3 flex justify-between items-center">
                <Link to="/" className="text-2xl font-bold text-primary flex items-center gap-2">
                    Guardianes de Sonrisas
                </Link>

                <div className="flex items-center gap-6">
                    <Link to="/search" className="text-gray-700 hover:text-primary transition-colors font-medium">
                        Buscar Cuidadores
                    </Link>

                    {user ? (
                        <div className="flex items-center gap-4">
                            <span className="text-sm text-gray-600">Hola, {user.full_name}</span>
                            <Link 
                                to={`/dashboard/${user.role}`} 
                                className="bg-primary text-white px-4 py-2 rounded-full hover:bg-primary/90 transition flex items-center gap-2"
                            >
                                <User size={18} /> Panel
                            </Link>
                            <button onClick={logout} className="text-sm text-red-500 hover:text-red-700 transition">
                                Salir
                            </button>
                        </div>
                    ) : (
                        <div className="flex items-center gap-3">
                            <Link to="/login" className="text-gray-700 hover:text-primary transition font-medium">Ingresar</Link>
                            <Link to="/register" className="bg-primary text-white px-5 py-2 rounded-full hover:bg-primary/90 transition shadow-md hover:shadow-lg font-medium">
                                Registrarse
                            </Link>
                        </div>
                    )}
                </div>
            </div>
        </nav>
    );
};

export default Navbar;
